public static boolean containsIgnoreCase(String str, String searchStr) {
    if (str == null || searchStr == null) {
        return false;
    }
    final int len = searchStr.length();
    final int max = str.length() - len;
    for (int i = 0; i <= max; i++) {
        if (regionMatches(str, i, searchStr)) {
            return true;
        }
    }
    return false;
}

private static boolean regionMatches(String str, int strStart, String searchStr) {
    if (strStart < 0 || strStart + searchStr.length() > str.length()) {
        return false;
    }
    for (int i = 0; i < searchStr.length(); i++) {
        char c1 = str.charAt(strStart + i);
        char c2 = searchStr.charAt(i);
        if (c1 != c2) {
            // Try converting both characters to uppercase and compare
            char u1 = Character.toUpperCase(c1);
            char u2 = Character.toUpperCase(c2);
            if (u1 != u2) {
                // If uppercase doesn't match, try lowercase
                if (Character.toLowerCase(u1) != Character.toLowerCase(u2)) {
                    return false;
                }
            }
        }
    }
    return true;
}

