protected double getInitialDomain(double p) {
    double ret;
    double d = getDenominatorDegreesOfFreedom();
    if (d <= 2.0) {
        // Use a reasonable default when denominator degrees of freedom <= 2
        // The mode of F distribution is used as initial domain when d1 > 2
        // For d1 <= 2, we use a safe positive value
        ret = 1.0;
    } else {
        // use mean
        ret = d / (d - 2.0);
    }
    return ret;
}

protected double getInitialDomain(double p) {
    double ret;
    double d = getDenominatorDegreesOfFreedom();
    if (d <= 2.0) {
        // use median for small denominator degrees of freedom
        ret = getMedian(p);
    } else {
        // use mean
        ret = d / (d - 2.0);
    }
    return ret;
}

private double getMedian(double p) {
    // For F-distribution with small denominator degrees of freedom,
    // use a reasonable initial value that avoids division by zero
    // This is a simplified approximation - in practice you might want
    // a more sophisticated approach
    double numeratorDF = getNumeratorDegreesOfFreedom();
    double denominatorDF = getDenominatorDegreesOfFreedom();

    // Use a reasonable starting point that avoids infinity
    // For denominator DF = 2, the mean doesn't exist, so we use a value
    // that should work well for bracketing
    if (denominatorDF <= 2.0) {
        return 1.0; // Reasonable starting point for bracketing
    } else {
        return denominatorDF / (denominatorDF - 2.0);
    }
}

