private static BomCharset detectCharsetFromBom(ByteBuffer byteData) {
    if (byteData.remaining() < 2) return null;

    byteData.mark();
    byte[] bom = new byte[4];
    int bytesRead = 0;

    while (byteData.hasRemaining() && bytesRead < 4) {
        bom[bytesRead++] = byteData.get();
    }
    byteData.reset();

    // Check for UTF-8 BOM: EF BB BF
    if (bytesRead >= 3 && (bom[0] & 0xFF) == 0xEF && (bom[1] & 0xFF) == 0xBB && (bom[2] & 0xFF) == 0xBF) {
        return new BomCharset("UTF-8", 3);
    }

    // Check for UTF-16 BE BOM: FE FF
    if (bytesRead >= 2 && (bom[0] & 0xFF) == 0xFE && (bom[1] & 0xFF) == 0xFF) {
        return new BomCharset("UTF-16BE", 2);
    }

    // Check for UTF-16 LE BOM: FF FE
