protected void burstToken(String token, boolean stopAtNonOption)
{
    // if the token is just a single hyphen, add it and return
    if ("-".equals(token))
    {
        tokens.add(token);
        return;
    }

    // if the token starts with two hyphens, add it as is and return
    if (token.startsWith("--"))
    {
        tokens.add(token);
        return;
    }

    int tokenLength = token.length();

    for (int i = 1; i < tokenLength; i++)
    {
        String ch = String.valueOf(token.charAt(i));
        boolean hasOption = options.hasOption(ch);

        if (hasOption)
