    final int len = str.length();
    // [Issue#133]: beware of super long indexes; assume we never
    // have arrays over 2 billion entries so ints are fine.
    if (len == 0 || len > 10) {
        return -1;
    }
    // Check for leading zero (except for single "0")
    char c = str.charAt(0);
    if (c <= '0') {
        // Leading zero not allowed for multi-digit numbers
        if (c == '0' && len > 1) {
            return -1;
        }
        // Single "0" is valid, but if it's not '0' then it's below '0' (invalid)
        if (c < '0') {
            return -1;
        }
    } else if (c > '9') {
        return -1;
    }
    // Check remaining characters
    for (int i = 1; i < len; ++i) {
        c = str.charAt(i);
        if (c > '9' || c < '0') {
            return -1;
        }
    }
    if (len == 10) {
        long l = NumberInput.parseLong(str);
        if (l > Integer.MAX_VALUE) {
            return -1;
        }
