            (year, monthOfYear, dayOfMonth,
             hourOfDay, minuteOfHour, secondOfMinute, millisOfSecond);
    }

    // First try as Julian date
    long instant;
    try {
        instant = iJulianChronology.getDateTimeMillis
            (year, monthOfYear, dayOfMonth,
             hourOfDay, minuteOfHour, secondOfMinute, millisOfSecond);
        if (instant < iCutoverMillis) {
            // Valid Julian date that's before cutover
            return instant;
        }
    } catch (IllegalFieldValueException e) {
        // Not a valid Julian date, try Gregorian
    }

    // Try as Gregorian date
    instant = iGregorianChronology.getDateTimeMillis
        (year, monthOfYear, dayOfMonth,
         hourOfDay, minuteOfHour, secondOfMinute, millisOfSecond);

    if (instant < iCutoverMillis) {
        // Gregorian date exists but is before cutover, which means
        // the date should have been valid in Julian chronology
        // If we're here, the Julian attempt failed, so this is invalid
        throw new IllegalArgumentException("Specified date does not exist");
    }

    return instant;
