public char[] expandCurrentSegment()
{
    final char[] curr = _currentSegment;
    final int len = curr.length;

    // Double the size until we reach MAX_SEGMENT_LEN, then add fixed amounts
    int newLen;
    if (len < MAX_SEGMENT_LEN) {
        // Grow by 50% up to MAX_SEGMENT_LEN
        newLen = Math.min(MAX_SEGMENT_LEN, len + (len >> 1));
        // But ensure we grow by at least 1 character
        if (newLen == len) {
            newLen = len + 1;
        }
    } else {
        // Once at maximum segment size, grow by smaller increments
        newLen = len + (MAX_SEGMENT_LEN >> 2); // Grow by 25% of MAX_SEGMENT_LEN
        // Ensure we don't exceed array size limits
        if (newLen < 0) { // Handle integer overflow
            newLen = Integer.MAX_VALUE;
        }
    }
    return (_currentSegment = Arrays.copyOf(curr, newLen));
}

public char[] expandCurrentSegment()
{
